sys_variable_value.value:
(function execute(inputs, outputs) {
  var certificateService = new CertificateService();
  var certificate;

  try {
    certificate = certificateService.issueCertificate(inputs.certificateRequestGr);

    var requestId = certificate.request_id;
    if (requestId) {
      outputs.request_id = requestId;
      return;
    }
  } catch (error) {
  	if (error instanceof HttpError) {
      outputs.error_reason = error.reason;
    } else {
      outputs.error_reason = error.message;
    }

    return;
  }

  outputs.serial_number = certificate.serial_number;
  outputs.delivery_format = certificate.delivery_format;
  outputs.certificate = certificate.certificate;
})(inputs, outputs);

